# LITMUS recompute script for percent_change.v1 (DESIGN §3.2: no script, no flag).
# Self-contained, stdlib-only, network-less, deterministic.
OLD_VALUE = 3004
NEW_VALUE = 4361
REPORTED_PCT_CHANGE = 31.1
TOLERANCE = 0.09080777339047272


def _fmt(value):
    if isinstance(value, bool):
        value = int(value)
    if isinstance(value, int):
        return str(value)
    if isinstance(value, float) and value.is_integer():
        return str(int(value))
    return repr(value)


computed = 100.0 * (NEW_VALUE - OLD_VALUE) / OLD_VALUE
if abs(computed - REPORTED_PCT_CHANGE) <= TOLERANCE:
    print('OK')
else:
    print('MISMATCH reported=' + _fmt(REPORTED_PCT_CHANGE) + ' computed=' + _fmt(computed))
